import { memo, useMemo, useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { ArrowRight, Heart, MessageCircle, Image, Play, ChefHat } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { cn } from "@/lib/utils";

// Get responsive display count based on window width
const useResponsiveCount = () => {
  const [count, setCount] = useState(4);
  
  useEffect(() => {
    const updateCount = () => {
      const width = window.innerWidth;
      if (width < 640) setCount(2);
      else if (width < 1024) setCount(3);
      else setCount(4);
    };
    updateCount();
    window.addEventListener("resize", updateCount);
    return () => window.removeEventListener("resize", updateCount);
  }, []);
  
  return count;
};

// Post Card Component
const RecentPostCard = memo(({ post }: { post: any }) => {
  const navigate = useNavigate();
  const { t } = useTranslation();
  const { getLocalizedField } = useLocalizedContent();
  
  const isRecipe = post.post_type === "recipe";
  const title = isRecipe
    ? getLocalizedField(post, "recipe_name") || post.recipe_name
    : null;
  const content = getLocalizedField(post, "content") || post.content;
  const displayText = title || content;
  const coverImage = post.image_urls?.[0] || null;
  const authorName = post.author?.display_name || t("community.anonymous", "匿名用户");
  const authorAvatar = post.author?.avatar_url;
  
  return (
    <Card
      className="group cursor-pointer overflow-hidden hover:shadow-lg transition-all duration-300 border-border/50 bg-card"
      onClick={() => navigate(`/community/post/${post.id}`)}
    >
      {/* Image Container */}
      <div className="relative aspect-[16/10] overflow-hidden bg-muted">
        {coverImage ? (
          <img
            src={coverImage}
            alt={displayText || ""}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
            loading="lazy"
          />
        ) : post.video_url ? (
          <video
            src={`${post.video_url}#t=0.001`}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
            preload="metadata"
            muted
            playsInline
            crossOrigin="anonymous"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-primary/20 to-primary/5">
            {isRecipe ? (
              <ChefHat className="w-12 h-12 text-primary/40" />
            ) : (
              <Image className="w-12 h-12 text-primary/40" />
            )}
          </div>
        )}

        {/* Recipe Badge - only show for recipe posts */}
        {isRecipe && (
          <Badge className="absolute top-2 left-2 text-xs font-medium bg-accent text-accent-foreground">
            {t("community.recipe", "食谱")}
          </Badge>
        )}

        {/* Video indicator */}
        {post.video_url && (
          <div className="absolute top-2 right-2 w-6 h-6 rounded-full bg-black/50 flex items-center justify-center">
            <Play className="w-3 h-3 text-white fill-white" />
          </div>
        )}

        {/* Multi-image indicator */}
        {!post.video_url && post.image_urls?.length > 1 && (
          <div className="absolute top-2 right-2 bg-black/50 text-white text-[10px] px-1.5 py-0.5 rounded-full">
            {post.image_urls.length}
          </div>
        )}
      </div>

      {/* Content */}
      <div className="p-3 space-y-2">
        <p className="font-medium text-sm leading-tight line-clamp-2 text-foreground group-hover:text-primary transition-colors">
          {displayText}
        </p>

        <div className="flex items-center justify-between">
          {/* Author */}
          <div className="flex items-center gap-1.5 min-w-0">
            <Avatar className="w-4 h-4">
              <AvatarImage src={authorAvatar || undefined} />
              <AvatarFallback className="text-[8px]">{authorName[0]}</AvatarFallback>
            </Avatar>
            <span className="text-xs text-muted-foreground truncate max-w-[60px]">{authorName}</span>
          </div>

          {/* Stats */}
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <span className="flex items-center gap-0.5">
              <Heart className="w-3 h-3" />
              {post.likes_count || 0}
            </span>
            <span className="flex items-center gap-0.5">
              <MessageCircle className="w-3 h-3" />
              {post.comments_count || 0}
            </span>
          </div>
        </div>
      </div>
    </Card>
  );
});
RecentPostCard.displayName = "RecentPostCard";

// Loading Skeleton
const LoadingSkeleton = memo(() => {
  const displayCount = useResponsiveCount();
  return (
    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
      {Array.from({ length: displayCount }).map((_, i) => (
        <Card key={i} className="overflow-hidden">
          <Skeleton className="aspect-[16/10] w-full" />
          <div className="p-3 space-y-2">
            <Skeleton className="h-4 w-full" />
            <Skeleton className="h-3 w-2/3" />
          </div>
        </Card>
      ))}
    </div>
  );
});
LoadingSkeleton.displayName = "RecentPostsSkeleton";

// Main Component
const RecentPostsSection = memo(() => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const displayCount = useResponsiveCount();
  const [showAll, setShowAll] = useState(false);

  const { data: posts = [], isLoading } = useQuery({
    queryKey: ["recent-home-posts"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("community_posts")
        .select(`
          id, content, content_en, content_zh, content_pt,
          image_urls, video_url, post_type,
          recipe_name, recipe_name_en, recipe_name_pt,
          likes_count, comments_count, shares_count, views_count,
          created_at,
          author:profiles!community_posts_author_id_fkey(id, display_name, avatar_url)
        `)
        .eq("status", "approved")
        .order("created_at", { ascending: false })
        .limit(12);

      if (error) throw error;
      return (data || []).map((p: any) => ({
        ...p,
        author: Array.isArray(p.author) ? p.author[0] : p.author,
      }));
    },
    staleTime: 5 * 60 * 1000,
  });

  const displayedPosts = useMemo(() => {
    return showAll ? posts : posts.slice(0, displayCount);
  }, [posts, displayCount, showAll]);

  const hasMore = posts.length > displayCount;

  if (!isLoading && posts.length === 0) return null;

  return (
    <section className="py-8 sm:py-12 px-4 bg-secondary/20">
      <div className="container mx-auto max-w-7xl">
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl sm:text-2xl font-bold text-foreground">
            {t("home.recentPosts.title", "近日食谱")}
          </h2>

          {hasMore && !showAll && (
            <Button
              variant="ghost"
              size="sm"
              className="text-primary hover:text-primary/80"
              onClick={() => setShowAll(true)}
            >
              <span className="flex items-center gap-1">
                {t("home.recentPosts.viewAll", "查看全部")}
                <ArrowRight className="w-4 h-4" />
              </span>
            </Button>
          )}

          {showAll && (
            <Button
              variant="ghost"
              size="sm"
              className="text-muted-foreground hover:text-foreground"
              onClick={() => setShowAll(false)}
            >
              <span className="flex items-center gap-1">
                {t("home.recentPosts.collapse", "收起")}
              </span>
            </Button>
          )}
        </div>

        {/* Content */}
        {isLoading ? (
          <LoadingSkeleton />
        ) : (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
            {displayedPosts.map((post: any) => (
              <RecentPostCard key={post.id} post={post} />
            ))}
          </div>
        )}
      </div>
    </section>
  );
});
RecentPostsSection.displayName = "RecentPostsSection";

export default RecentPostsSection;
